CREATE DATABASE SuperstoreDB;

-- Import the Sample Superstore CSV into the Superstore table before running these queries.

USE SuperstoreDB;

-- Business Question 1
-- What is the total sales generated by the company?

SELECT SUM(Sales) AS Total_Sales 
FROM Superstore;

-- Business Question 2
-- What is the total profit earned?

SELECT  SUM(Profit) AS Total_Profit 
FROM Superstore;

-- Business Question 3
-- How many orders were placed?

SELECT COUNT(DISTINCT Order_ID) AS Number_of_Orders
FROM Superstore;

-- Business Question 4
-- What is the average order value?

SELECT  AVG(OrderSales) AS Average_Order_Value
FROM
(
SELECT  Order_ID,
       SUM(Sales) AS OrderSales
FROM Superstore
GROUP BY Order_ID
) AS Orders;

-- Business Question 5
-- Which month generated the highest sales?

SELECT  
	YEAR(Order_Date) AS Sales_Year, 
    MONTH(Order_Date) AS Sales_Month ,
    SUM(Sales) AS Total_Sales 
FROM Superstore
GROUP BY Sales_Year,Sales_Month 
ORDER BY Total_Sales DESC
LIMIT 1;

-- Business Question 6
-- Which region has the highest sales?

SELECT
	Region,
    SUM(Sales) AS Total_Sales
FROM Superstore
GROUP BY Region
ORDER BY Total_Sales DESC
LIMIT 1;

-- Business Question 7
-- Which region generates the highest profit?

SELECT  
	Region,
    SUM(Profit) AS Total_Profit 
FROM Superstore
GROUP BY Region
ORDER BY Total_Profit DESC
LIMIT 1;

-- Business Question 8
-- Which state has the highest sales?

SELECT 
	State,
    SUM(Sales) AS Total_Sales 
FROM Superstore
GROUP BY State
ORDER BY Total_Sales DESC
LIMIT 1;

-- Business Question 9
-- Which city has the highest profit?

SELECT 
	City,
    SUM(Profit) AS Total_Profit 
FROM Superstore
GROUP BY City
ORDER  BY Total_Profit DESC
LIMIT 1;

-- Business Question 10
-- Which region has the lowest profit margin?

SELECT 
	Region,
    SUM(Profit) AS Total_Profit,
    SUM(Sales) AS Total_Sales,
    ROUND(SUM(Profit)*100.0/SUM(Sales),2) AS Profit_margin  
FROM Superstore
GROUP BY Region
ORDER  BY Profit_margin ASC
LIMIT 1;

--  Business Question 11
--  Which category generates the highest sales?

SELECT 
	Category,
    SUM(Sales) AS Total_Sales 
FROM  Superstore
GROUP  BY  Category
ORDER  BY Total_Sales DESC
LIMIT 1 ;

-- Business Question 12
-- Which sub-category generates the highest profit?

SELECT 
	Sub_Category,
    SUM(Profit) AS Total_Profit 
FROM Superstore
GROUP BY Sub_Category
ORDER BY Total_Profit DESC
LIMIT 1;

-- Business Question 13
-- What are the Top 10 best-selling products?

SELECT 
	Product_ID,Product_Name,
    SUM(Sales) AS Total_Sales 
FROM Superstore
GROUP BY Product_ID,Product_Name
ORDER BY Total_Sales DESC
LIMIT 10;

-- Business Question 14
-- Which products are making losses?

SELECT 
	Product_Name,
    SUM(Profit) AS Total_Profit
FROM Superstore
GROUP BY Product_Name
HAVING SUM(Profit) <0
ORDER BY Total_Profit;

-- Business Question 15
-- Which products have never generated a profit?

SELECT 
	Product_ID, Product_Name 
FROM Superstore
GROUP BY Product_ID,Product_Name
HAVING MAX(Profit) <=0;

-- Business Question 16
-- Who are the Top 10 customers by sales?

SELECT 
	Customer_ID,Customer_Name,
    SUM(Sales) AS Total_Sales 
FROM Superstore
GROUP BY Customer_ID,Customer_Name 
ORDER BY Total_Sales DESC
LIMIT 10;

-- Business Question 17
-- Who are the Top 10 customers by profit?

SELECT
	Customer_ID,Customer_Name,
    SUM(Profit) AS Total_Profit
FROM Superstore
GROUP BY Customer_ID,Customer_Name 
ORDER BY Total_Profit DESC
LIMIT 10;

-- Business Question 18
-- Which customers placed the most orders?

SELECT 
	Customer_ID,Customer_Name,
    COUNT(DISTINCT Order_ID) AS Number_Of_Orders 
FROM Superstore
GROUP BY Customer_ID,Customer_Name
ORDER BY Number_Of_Orders DESC
LIMIT 1;

-- Business Question 19
-- Which customer has the highest average order value?

WITH ordervalue AS(
SELECT 
	Order_ID,Customer_ID,Customer_Name,
    SUM(Sales) AS Total_Value_Of_Orders 
FROM Superstore
GROUP BY Order_ID,Customer_ID,Customer_Name
)
SELECT 
	Customer_ID,Customer_Name,
    AVG(Total_Value_of_Orders) AS Average_order_value
FROM ordervalue
GROUP BY Customer_ID,Customer_Name
ORDER BY Average_order_value DESC
LIMIT 1;

-- Business Question 20
-- Which customers have generated negative profit?

SELECT
	Customer_ID,Customer_Name,
    SUM(Profit) AS Total_Profit 
FROM Superstore
GROUP BY Customer_ID,Customer_Name
HAVING SUM(Profit) <0
ORDER BY Total_Profit;

-- Business Question 21
-- What is the month-over-month sales growth?

WITH MonthlySales AS
(
    SELECT
        YEAR(Order_Date) AS Sales_Year,
        MONTH(Order_Date) AS Sales_Month,
        SUM(Sales) AS Total_Sales
    FROM Superstore
    GROUP BY
        YEAR(Order_Date),
        MONTH(Order_Date)
)

SELECT
    Sales_Year,
    Sales_Month,
    Total_Sales,
    LAG(Total_Sales) OVER (
    ORDER BY Sales_Year, Sales_Month) AS Previous_month_total_Sales,   
    ROUND(((Total_Sales -LAG(Total_Sales) OVER (ORDER BY Sales_Year ,Sales_Month)) * 100.0) /
        NULLIF(LAG(Total_Sales) OVER (ORDER BY Sales_Year,Sales_Month),0),2) AS MoM_Growth_Percentage
FROM MonthlySales;

-- Business Question 22
-- Calculate the running total of sales over time.

SELECT 
	Order_Date,SUM(Sales) AS Daily_Sales,
    SUM(SUM(Sales)) 
    OVER(
    ORDER BY Order_Date
    ) AS Running_Total
FROM Superstore
GROUP BY Order_Date
ORDER BY Order_Date;

-- Business Question 23
-- Compare each month's sales with the previous month.

WITH MonthlySales AS
(
    SELECT
        YEAR(Order_Date) AS Sales_Year,
        MONTH(Order_Date) AS Sales_Month,
        SUM(Sales) AS Total_Sales
    FROM Superstore
    GROUP BY
        YEAR(Order_Date),
        MONTH(Order_Date)
)

SELECT
    Sales_Year,
    Sales_Month,
    Total_Sales,
    LAG(Total_Sales) OVER (
    ORDER BY Sales_Year, Sales_Month) AS Previous_Sales,  
    (Total_Sales-LAG(Total_Sales) OVER (
    ORDER BY Sales_Year, Sales_Month)) AS Difference
    
FROM  MonthlySales;

-- Business Question 24
-- Rank products based on total sales within each category.

WITH  ProductSales AS
(
SELECT Category,Product_ID,Product_Name,SUM(Sales) AS Total_Sales
FROM  Superstore
GROUP BY Category,Product_ID,Product_Name
)

SELECT Category,Product_ID,Product_Name,Total_Sales,
    RANK() OVER(PARTITION BY Category ORDER  BY Total_Sales DESC ) AS Product_Rank
FROM  ProductSales
ORDER BY Category, Product_Rank;

-- Business Question 25
-- Rank customers within each region based on total profit.

WITH Customer_Profit AS
(
SELECT Region,Customer_ID,Customer_Name,SUM(Profit) AS Total_Profit
FROM Superstore
GROUP  BY Region,Customer_ID,Customer_Name
)

SELECT Region,Customer_ID,Customer_Name,Total_Profit,
    RANK() OVER(PARTITION BY Region ORDER BY Total_Profit DESC) AS Customer_Rank
FROM Customer_Profit
ORDER BY Region, Customer_Rank;

